import { type ReactNode } from 'react';

import { Label, Text } from 'react-aria-components';
import {
  Tooltip,
  TooltipTrigger,
} from '@/components/atoms/Tooltip/base/tooltip';
import { ConditionalTooltip } from '@/components/atoms/Tooltip';
import { useTruncation } from '@/hooks/use-truncation';
import { cx } from '@/utils/cx';
import { Hint } from './Hint';
import { HelpCircle } from '@untitledui/icons';

// ─── Types ───────────────────────────────────────────────────────────

export type LabelPosition = 'left' | 'top';
export type FieldSize = 'sm' | 'md' | 'full' | 'auto';

export type FieldWrapperProps = {
  label?: string;
  hint?: ReactNode;
  children: ReactNode;
  tooltip?: string;
  isRequired?: boolean;
  isInvalid?: boolean;
  isWarning?: boolean;
  fieldSize?: FieldSize;
  labelPosition?: LabelPosition;
  description?: string | ReactNode;
  id?: string;
  alignLabel?: 'center' | 'top';

  /** @deprecated */
  contentClassName?: string;
};

// ─── Style Maps ──────────────────────────────────────────────────────

const CONTROL_SIZE_STYLES: Record<FieldSize, string> = {
  sm: 'w-[180px]',
  md: 'w-[352px]',
  full: 'flex-1',
  auto: 'w-fit',
};

const LABEL_BASE_WIDTH = 'w-[160px]';

// ─── Helpers ─────────────────────────────────────────────────────────

function getControlClassName(size: FieldSize): string {
  return cx('flex min-w-0 flex-col gap-0.5', CONTROL_SIZE_STYLES[size]);
}

// ─── Component ───────────────────────────────────────────────────────

export function FieldWrapper({
  id = '',
  labelPosition = 'left',
  label,
  hint,
  children,
  isRequired,
  isInvalid,
  isWarning,
  tooltip,
  fieldSize = 'md',
  description,
  alignLabel = 'center',
}: FieldWrapperProps) {
  const fieldId = id;
  const descriptionId = `${fieldId}-description`;

  const isLeft = labelPosition === 'left';
  const hasAdornments = isRequired || tooltip;

  const { ref: labelRef, isTruncated: isLabelTruncated } =
    useTruncation<HTMLSpanElement>('y');

  const { ref: descRef, isTruncated: isDescTruncated } =
    useTruncation<HTMLSpanElement>('y');

  // ── Shared pieces ───────────────────────────────────────────────

  const descriptionContent = description && (
    <ConditionalTooltip
      text={description}
      isTruncated={isDescTruncated}
    >
      <Text
        id={descriptionId}
        slot="description"
        ref={descRef}
        className="line-clamp-2 text-xs leading-snug text-gray-500"
      >
        {description}
      </Text>
    </ConditionalTooltip>
  );

  const hintContent = hint && (
    <Hint
      isInvalid={isInvalid}
      isWarning={isWarning}
    >
      {hint}
    </Hint>
  );

  // ── Label + Description ─────────────────────────────────────────

  const labelContent = label && (
    <Label
      htmlFor={fieldId}
      className="flex items-start gap-1 text-sm font-normal leading-snug text-gray-900"
      aria-label={label}
    >
      <ConditionalTooltip
        text={label}
        isTruncated={isLabelTruncated}
      >
        <span
          ref={labelRef}
          className="min-w-0 line-clamp-2"
        >
          {label}
        </span>
      </ConditionalTooltip>

      {hasAdornments && (
        <span className="inline-flex shrink-0 items-center gap-1">
          {isRequired && (
            <span
              className={cx(
                'font-bold',
                isInvalid ? 'text-red-500' : 'text-brand-secondary',
              )}
              aria-hidden="true"
            >
              *
            </span>
          )}

          {tooltip && (
            <Tooltip
              title={tooltip}
              placement="top"
            >
              <TooltipTrigger
                isDisabled={false}
                className="shrink-0 cursor-pointer text-fg-quaternary
                           transition duration-200
                           hover:text-fg-quaternary_hover
                           focus:text-fg-quaternary_hover"
              >
                <HelpCircle className="size-4 mt-[2px]" />
              </TooltipTrigger>
            </Tooltip>
          )}
        </span>
      )}
    </Label>
  );

  // ── TOP layout ──────────────────────────────────────────────────

  if (!isLeft) {
    return (
      <div data-invalid={isInvalid || undefined}>
        <div className={getControlClassName(fieldSize)}>
          {(labelContent || descriptionContent) && (
            <div className="flex flex-col">
              {labelContent}
              {descriptionContent}
            </div>
          )}

          {children}

          {hintContent}
        </div>
      </div>
    );
  }

  // ── LEFT layout ─────────────────────────────────────────────────

  return (
    <div
      className="flex items-start gap-2"
      data-invalid={isInvalid || undefined}
    >
      {(label || descriptionContent) && (
        <div
          className={cx(
            'flex min-h-[36px]',
            alignLabel === 'center' && 'items-center',
            alignLabel === 'top' && 'items-start',
          )}
        >
          <div className={cx('flex shrink-0 flex-col', LABEL_BASE_WIDTH)}>
            {labelContent}
            {descriptionContent}
          </div>
        </div>
      )}

      <div className={getControlClassName(fieldSize)}>
        {children}
        {hintContent}
      </div>
    </div>
  );
}
